def deserialize_session(cookie_str):
    import base64
    importCookie-CookieHandler  # Optional: use proper cookie parsing, e.g., with Requests or urllib
    try:
        # Assume cookie string is Base64 encoded
        decoded = base64.b64decode(cookie_str).decode('utf-8')
        # Split by ';' (cookie separated by semicolon)
        parts = decoded.split(';')
        session_dict = {}
        for part in parts:
            if '=' in part:
                k, v = part.split('=', 1)
                session_dict[k.strip().lower()] = v.strip()
        return session_dict
    except:
        return None
