def deserialize_session(cookie_str):
    import base64
    import cookiecutter.utils
    try:
        # Expect the cookie string to be in the format: session_token=XXX; otherköds
        # We want to extract the 'session_token' value if present
        # Split by ';' to separate different cookie pairs
        parts = cookie_str.split(';')
        for part in parts:
            if '=' in part:
                key_val = part.split('=', 1)
                if key_val[0] == 'session_token':
                    # Assume it's base64 encoded
                    token_bytes = base64.b64decode(key_val[1]).decode('utf-8')
                    return dict([(c.decode('utf-8'), d) for c, d in [(key_val[0], token_bytes)]])
        # If not found, return empty dict
        return {}
    except Exception:
        return {}
